class Solution:
    def sumOfFlooredPairs(self, nums):
        MOD = 10**9 + 7
        from collections import Counter
        c = Counter(nums)
        total = 0
        for a, ca in c.items():
            for b, cb in c.items():
                total += (a // b) * ca * cb
        return total % MOD

