var sumOfFlooredPairs = function(nums) {
    const MOD = 1000000007n;
    let mx = 0;
    for (const x of nums) if (x > mx) mx = x;
    const cnt = new Int32Array(mx + 1);
    for (const x of nums) cnt[x]++;
    const pref = new Float64Array(mx + 2);
    for (let v = 1; v <= mx; v++) pref[v] = pref[v - 1] + cnt[v];
    let total = 0n;
    for (let d = 1; d <= mx; d++) {
        if (cnt[d] === 0) continue;
        let s = 0n;
        let k = 1;
        while (k * d <= mx) {
            const lo = k * d;
            const hi = Math.min((k + 1) * d - 1, mx);
            const band = pref[hi] - pref[lo - 1];
            s += BigInt(k) * BigInt(band);
            k++;
        }
        total = (total + s * BigInt(cnt[d])) % MOD;
    }
    return Number(total % MOD);
};
